example.code:
// Good - explicit return type on exported function
export function parseConfig(raw: string): Config {
  return ConfigSchema.parse(JSON.parse(raw)); // see TY405 for boundary validation
}

// Bad - inferred return type can change unexpectedly
export function parseConfig(raw: string) {
  return JSON.parse(raw);
}

// Good - interface for object shape
interface User {
  readonly id: string;
  name: string;
}

// Good - type for union
type Result<T> = { ok: true; value: T } | { ok: false; error: Error };

// Good - constrained generic
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

// Good - generic interface
interface Repository<T extends { id: string }> {
  findById(id: string): Promise<T | undefined>;
  save(entity: T): Promise<void>;
}

// Bad - unconstrained, unclear intent
function getProperty(obj: any, key: string): any {
  return obj[key];
}

// Good
type UserUpdate = Partial<Pick<User, "name" | "email">>;
type UserIndex = Record<string, User>;
type ImmutableUser = Readonly<User>;

// Bad - manual reconstruction
type UserUpdate = {
  name?: string;
  email?: string;
};

// Good - literal type
type Direction = "north" | "south" | "east" | "west";

// Good - const assertion
const ROUTES = {
  home: "/",
  about: "/about",
  users: "/users",
} as const;

type Route = (typeof ROUTES)[keyof typeof ROUTES];

// Good - discriminated union
type Shape =
  | { kind: "circle"; radius: number }
  | { kind: "rectangle"; width: number; height: number };

function area(shape: Shape): number {
  switch (shape.kind) {
    case "circle":
      return Math.PI * shape.radius ** 2;
    case "rectangle":
      return shape.width * shape.height;
  }
}

// Good - branded types with distinct symbols
declare const userIdBrand: unique symbol;
type UserId = string & { readonly [userIdBrand]: true };

declare const orderIdBrand: unique symbol;
type OrderId = string & { readonly [orderIdBrand]: true };

function createUserId(id: string): UserId {
  return id as UserId;
}

function getUser(id: UserId): User | undefined {
  // implementation
  return undefined;
}

// Compiler error: OrderId is not assignable to UserId
// getUser(orderId);

// Good - template literal type
type EventName = `on${Capitalize<string>}`;
type CSSUnit = `${number}${"px" | "em" | "rem" | "%"}`;
type APIRoute = `/api/v${number}/${string}`;

function setStyle(prop: string, value: CSSUnit): void { ... }

// Good - union type
type Status = "active" | "inactive" | "pending";

// Good - const object when values differ from keys
const HttpStatus = {
  Ok: 200,
  NotFound: 404,
  ServerError: 500,
} as const;
type HttpStatus = (typeof HttpStatus)[keyof typeof HttpStatus];

// Avoid - TypeScript enum
enum Status {
  Active = "active",
  Inactive = "inactive",
  Pending = "pending",
}
